'use client';

import { type JSX } from 'react';
import type { EcomLocale } from '@/lib/locales';

interface Subscriber {
  email: string;
  subscribedAt: string;
}

interface AdminNewsletterPanelProps {
  locale: EcomLocale;
  loading: boolean;
  error: string;
  subscribers: Subscriber[];
}

function exportCsv(subscribers: Subscriber[]): void {
  const rows = ['email,subscribedAt', ...subscribers.map((s) => `${s.email},${s.subscribedAt}`)];
  const blob = new Blob([rows.join('\n')], { type: 'text/csv' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `newsletter-subscribers-${new Date().toISOString().slice(0, 10)}.csv`;
  a.click();
  URL.revokeObjectURL(url);
}

export function AdminNewsletterPanel({ locale, loading, error, subscribers }: AdminNewsletterPanelProps): JSX.Element {
  const isEmpty = subscribers.length === 0 && error.length === 0 && !loading;
  const showList = subscribers.length > 0 && error.length === 0 && !loading;
  const loadingLabel = locale === 'pl' ? 'Ładowanie…' : 'Loading…';
  const noSubscribersLabel = locale === 'pl' ? 'Brak subskrybentów.' : 'No subscribers yet.';
  const headingLabel = locale === 'pl' ? 'Subskrybenci newslettera' : 'Newsletter subscribers';
  const exportLabel = locale === 'pl' ? 'Eksportuj CSV' : 'Export CSV';
  const emailHeader = 'Email';
  const dateHeader = locale === 'pl' ? 'Data' : 'Date';

  return (
    <div style={{ borderTop: '1px solid rgba(210,116,102,0.2)', marginTop: '2rem', paddingTop: '1.5rem' }}>
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '1rem' }}>
        <div className='type-label' style={{ color: 'var(--coral-red)' }}>
          {headingLabel}
          {!loading && subscribers.length > 0 && (
            <span style={{ marginLeft: '0.5rem', opacity: 0.6 }}>({subscribers.length})</span>
          )}
        </div>
        {showList && (
          <button
            onClick={() => { exportCsv(subscribers); }}
            className='type-label'
            style={{
              color: 'var(--coral-red)',
              border: '1px solid rgba(210,116,102,0.4)',
              padding: '0.2rem 0.75rem',
              background: 'transparent',
              cursor: 'pointer',
            }}
          >
            {exportLabel}
          </button>
        )}
      </div>

      {loading && (
        <div className='type-label' style={{ color: 'var(--muted)', padding: '1rem 0' }}>{loadingLabel}</div>
      )}
      {!loading && error.length > 0 && (
        <div className='type-label' style={{ color: 'var(--coral-red)', padding: '1rem 0' }}>{error}</div>
      )}
      {isEmpty && (
        <div className='type-label' style={{ color: 'var(--muted)', padding: '1rem 0' }}>{noSubscribersLabel}</div>
      )}
      {showList && (
        <div style={{ border: '1px solid rgba(210,116,102,0.2)', overflow: 'hidden' }}>
          <div style={{
            display: 'grid',
            gridTemplateColumns: '1fr auto',
            gap: '1rem',
            padding: '0.65rem 1rem',
            background: 'rgba(210,116,102,0.06)',
            borderBottom: '1px solid rgba(210,116,102,0.2)',
          }}>
            {[emailHeader, dateHeader].map((h) => (
              <div key={h} className='type-label' style={{ color: 'var(--coral-red)', fontSize: '0.6rem', letterSpacing: '0.12em' }}>{h}</div>
            ))}
          </div>
          {subscribers.map((sub) => {
            const date = new Date(sub.subscribedAt).toLocaleDateString(
              locale === 'pl' ? 'pl-PL' : 'en-GB',
              { day: '2-digit', month: 'short', year: 'numeric' },
            );
            return (
              <div
                key={sub.email}
                style={{
                  display: 'grid',
                  gridTemplateColumns: '1fr auto',
                  gap: '1rem',
                  padding: '0.75rem 1rem',
                  borderBottom: '1px solid rgba(210,116,102,0.1)',
                  alignItems: 'center',
                }}
              >
                <div style={{ fontFamily: 'var(--font-mono)', fontSize: '0.7rem', color: 'var(--muted)', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                  {sub.email}
                </div>
                <div style={{ fontFamily: 'var(--font-mono)', fontSize: '0.65rem', color: 'var(--muted)', whiteSpace: 'nowrap' }}>
                  {date}
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

import { type NextRequest, NextResponse } from 'next/server';
import { getDb } from '@/lib/mongodb';
import { ORDERS_COLLECTION, type Order } from '@/lib/orders';
import { checkRateLimit, getClientIp } from '@/lib/rate-limit';
import { ensureAppIndexes } from '@/lib/db-indexes';
import { buildValidatedCheckoutOrder, isRecord } from '@/lib/checkout-order';

function readBankTransferDetails(): { enabled: boolean; accountName: string; iban: string; bic: string; bankName: string } {
  const iban = process.env['BANK_TRANSFER_IBAN']?.trim() ?? '';
  const accountName = process.env['BANK_TRANSFER_ACCOUNT_NAME']?.trim() ?? '';
  return {
    enabled: process.env['BANK_TRANSFER_ENABLED']?.trim() === 'true' || (iban !== '' && accountName !== ''),
    accountName,
    iban,
    bic: process.env['BANK_TRANSFER_BIC']?.trim() ?? '',
    bankName: process.env['BANK_TRANSFER_BANK_NAME']?.trim() ?? '',
  };
}

export async function POST(req: NextRequest): Promise<NextResponse> {
  void ensureAppIndexes();
  const ip = getClientIp(req);
  const { allowed, retryAfterSec } = checkRateLimit(`bank_transfer:${ip}`, 10, 60 * 60 * 1000);
  if (!allowed) {
    return NextResponse.json(
      { error: 'Too many attempts. Please try again later.' },
      { status: 429, headers: { 'Retry-After': String(retryAfterSec) } },
    );
  }

  const bankDetails = readBankTransferDetails();
  if (!bankDetails.enabled) {
    return NextResponse.json({ error: 'Bank transfer is not available.' }, { status: 503 });
  }

  let body: unknown;
  try {
    body = await req.json();
  } catch {
    return NextResponse.json({ error: 'Invalid JSON' }, { status: 400 });
  }
  if (!isRecord(body)) {
    return NextResponse.json({ error: 'Invalid payload' }, { status: 400 });
  }

  const result = await buildValidatedCheckoutOrder(body);
  if (!result.ok) {
    return NextResponse.json({ error: result.error }, { status: result.status });
  }

  const {
    orderId, userId, email, pricedItems,
    shippingSelection, shippingAddress, inpostPoint,
    subtotal, discount, promoCode, total,
  } = result.order;

  const now = new Date().toISOString();
  const order: Omit<Order, '_id'> = {
    orderId,
    ...(userId !== undefined ? { userId } : {}),
    email,
    status: 'pending_payment',
    paymentMethod: 'bank_transfer',
    items: pricedItems,
    shippingMethod: shippingSelection.shippingMethod,
    shippingPrice: shippingSelection.shippingPrice,
    shippingCarrier: shippingSelection.shippingCarrier,
    shippingService: shippingSelection.shippingService,
    ...(inpostPoint !== null ? { inpostPoint } : {}),
    shippingAddress,
    subtotal,
    discount,
    promoCode,
    total,
    createdAt: now,
  };

  try {
    const db = await getDb();
    await db.collection(ORDERS_COLLECTION).insertOne(order);
  } catch {
    return NextResponse.json({ error: 'Failed to create order. Please try again.' }, { status: 500 });
  }

  return NextResponse.json({
    orderId,
    email,
    total,
    bankDetails: {
      accountName: bankDetails.accountName,
      iban: bankDetails.iban,
      bic: bankDetails.bic,
      bankName: bankDetails.bankName,
      reference: orderId,
    },
  });
}

import { type NextRequest, NextResponse } from 'next/server';
import { getDb } from '@/lib/mongodb';
import { ORDERS_COLLECTION } from '@/lib/orders';
import { checkRateLimit, getClientIp } from '@/lib/rate-limit';
import { capturePayPalOrder } from '@/lib/paypal';
import { sendOrderConfirmation } from '@/lib/email';
import { fulfillInpostOrder } from '@/lib/inpost';
import { serializeOrder } from '@/lib/orders';

const ORDER_ID_RE = /^ARC-\d{4}-[0-9A-F]{8}$/;

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === 'object' && value !== null && !Array.isArray(value);
}

function readString(value: unknown): string {
  return typeof value === 'string' ? value.trim() : '';
}

async function handleFulfillment(collection: any, order: any): Promise<void> {
  const emailClaim = await collection.updateOne(
    { _id: order._id, confirmationEmailQueuedAt: { $exists: false } },
    { $set: { confirmationEmailQueuedAt: new Date().toISOString() } },
  ).catch(() => ({ modifiedCount: 0 }));

  if (emailClaim.modifiedCount > 0) {
    await sendOrderConfirmation(serializeOrder(order)).catch(() => undefined);
    await fulfillInpostOrder(serializeOrder(order)).catch(() => undefined);
  }
}

export async function POST(req: NextRequest): Promise<NextResponse> {
  const ip = getClientIp(req);
  const { allowed, retryAfterSec } = checkRateLimit(`paypal-capture:${ip}`, 20, 60 * 60 * 1000);
  if (!allowed) {
    return NextResponse.json(
      { error: 'Too many attempts. Please try again later.' },
      { status: 429, headers: { 'Retry-After': String(retryAfterSec) } },
    );
  }

  let body: unknown;
  try {
    body = await req.json();
  } catch {
    return NextResponse.json({ error: 'Invalid JSON' }, { status: 400 });
  }

  if (!isRecord(body)) {
    return NextResponse.json({ error: 'Invalid payload' }, { status: 400 });
  }

  const orderId = readString(body['orderId']).toUpperCase();
  const paypalOrderId = readString(body['paypalOrderId']);

  if (!ORDER_ID_RE.test(orderId) || paypalOrderId.length === 0) {
    return NextResponse.json({ error: 'Invalid order data' }, { status: 400 });
  }

  const db = await getDb();
  const collection = db.collection(ORDERS_COLLECTION);

  const existing = await collection.findOne(
    { orderId, paymentMethod: 'paypal' },
    { projection: { status: 1, paypalOrderId: 1 } },
  );

  if (!existing) {
    return NextResponse.json({ error: 'Order not found' }, { status: 404 });
  }
  if (existing['status'] !== 'pending_payment') {
    return NextResponse.json({ orderId, status: existing['status'] }, { status: 200 });
  }

  try {
    const captureResult = await capturePayPalOrder(paypalOrderId);
    if (captureResult.status !== 'COMPLETED') {
      await collection.updateOne(
        { orderId, status: 'pending_payment' },
        { $set: { status: 'cancelled' } },
      ).catch(() => undefined);
      return NextResponse.json({ error: 'PayPal payment was declined.' }, { status: 422 });
    }
  } catch (err: unknown) {
    const msg = err instanceof Error ? err.message : 'PayPal capture failed';
    return NextResponse.json({ error: msg }, { status: 502 });
  }

  const updated = await collection.findOneAndUpdate(
    { orderId },
    { $set: { status: 'processing' } },
    { returnDocument: 'after' },
  ).catch(() => null);

  if (updated !== null && updated !== undefined) {
    await handleFulfillment(collection, updated);
  }

  return NextResponse.json({ orderId, status: 'processing' }, { status: 200 });
}

import { NextResponse } from 'next/server';

import { readEcommerceProviderSettings, type ProviderSettings } from '@/lib/providerSettings';

export const dynamic = 'force-dynamic';

type PublicInpostSettings = {
  enabled: boolean;
  geowidgetToken: string;
};

function envGeowidgetToken(): string {
  return process.env['NEXT_PUBLIC_INPOST_GEO_WIDGET_TOKEN']?.trim() ?? '';
}

function envStripePublishableKey(): string {
  return process.env['NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY']?.trim() ?? '';
}

function envPayPalClientId(): string {
  return process.env['NEXT_PUBLIC_PAYPAL_CLIENT_ID']?.trim() ?? '';
}

function envPayPalMode(): 'sandbox' | 'live' {
  return process.env['PAYPAL_MODE']?.trim() === 'live' ? 'live' : 'sandbox';
}

function envBankTransferDetails(): { enabled: boolean; accountName: string; iban: string; bic: string; bankName: string } {
  const iban = process.env['BANK_TRANSFER_IBAN']?.trim() ?? '';
  const accountName = process.env['BANK_TRANSFER_ACCOUNT_NAME']?.trim() ?? '';
  const enabledEnv = process.env['BANK_TRANSFER_ENABLED']?.trim() === 'true';
  const hasDetails = iban !== '' && accountName !== '';

  return {
    enabled: enabledEnv || hasDetails,
    accountName,
    iban,
    bic: process.env['BANK_TRANSFER_BIC']?.trim() ?? '',
    bankName: process.env['BANK_TRANSFER_BANK_NAME']?.trim() ?? '',
  };
}

function publicInpostSettings(settings: ProviderSettings | null): PublicInpostSettings {
  if (settings === null) return { enabled: true, geowidgetToken: envGeowidgetToken() };
  const inpost = settings.shipping.inpost;
  const dbToken = inpost.geowidgetToken.trim();
  const token = dbToken.length > 0 ? dbToken : envGeowidgetToken();
  return {
    enabled: inpost.enabled,
    geowidgetToken: inpost.enabled ? token : '',
  };
}

export async function GET(): Promise<NextResponse> {
  const settings = await readEcommerceProviderSettings();
  const inpost = publicInpostSettings(settings);

  const envStripeKey = envStripePublishableKey();
  const stripeEnabled = settings !== null
    ? settings.payment.stripe.enabled
    : envStripeKey !== '';

  let stripePublishableKey = '';
  if (stripeEnabled) {
    const dbKey = settings?.payment.stripe.publishableKey.trim() ?? '';
    stripePublishableKey = dbKey !== '' ? dbKey : envStripeKey;
  }

  const envPayPalId = envPayPalClientId();
  const paypalEnabled = settings !== null
    ? settings.payment.paypal.enabled
    : envPayPalId !== '';

  let paypalClientId = '';
  if (paypalEnabled) {
    const dbId = settings?.payment.paypal.clientId.trim() ?? '';
    paypalClientId = dbId !== '' ? dbId : envPayPalId;
  }

  const paypalMode: 'sandbox' | 'live' = settings?.payment.paypal.mode ?? envPayPalMode();

  const bankTransfer = envBankTransferDetails();

  return NextResponse.json(
    {
      payment: {
        payu: {
          enabled: settings?.payment.payu.enabled !== false,
        },
        stripe: {
          enabled: stripeEnabled,
          publishableKey: stripePublishableKey,
        },
        paypal: {
          enabled: paypalEnabled,
          clientId: paypalClientId,
          mode: paypalMode,
        },
        bankTransfer: {
          enabled: bankTransfer.enabled,
          accountName: bankTransfer.accountName,
          iban: bankTransfer.iban,
          bic: bankTransfer.bic,
          bankName: bankTransfer.bankName,
        },
      },
      shipping: {
        dpd: {
          enabled: settings?.shipping.dpd.enabled !== false,
        },
        inpost: {
          enabled: inpost.enabled,
          geowidgetToken: inpost.geowidgetToken,
        },
        pocztaPolska: {
          enabled: settings?.shipping.pocztaPolska.enabled !== false,
        },
      },
    },
    { headers: { 'Cache-Control': 'no-store' } }
  );
}

import { type NextRequest, NextResponse } from 'next/server';
import { Resend } from 'resend';
import { checkRateLimit, getClientIp } from '@/lib/rate-limit';

const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const MAX_MESSAGE_LENGTH = 4000;
const MAX_NAME_LENGTH = 160;
const MAX_SUBJECT_LENGTH = 200;

function readString(value: unknown, maxLength: number): string {
  return typeof value === 'string' ? value.trim().slice(0, maxLength) : '';
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === 'object' && value !== null && !Array.isArray(value);
}

function escapeHtml(value: string): string {
  return value
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
    .replaceAll('"', '&quot;')
    .replaceAll('\'', '&#39;');
}

function buildContactEmailHtml(name: string, email: string, subject: string, message: string): string {
  const lines = message.split('\n').map((line) => `<p style="margin:0 0 8px;">${escapeHtml(line)}</p>`).join('');
  return `
    <div style="margin:0;padding:0;background:#090909;color:#f5f1e8;font-family:Arial,Helvetica,sans-serif;">
      <div style="max-width:640px;margin:0 auto;padding:40px 24px;">
        <p style="letter-spacing:0.24em;text-transform:uppercase;color:#b6aa94;font-size:12px;margin:0 0 20px;">STARGATER</p>
        <h1 style="font-weight:400;font-size:22px;line-height:1.25;margin:0 0 24px;color:#f5f1e8;">New contact message</h1>
        <div style="border:1px solid #2b2b2b;background:#111;padding:24px;margin-bottom:20px;">
          <table role="presentation" cellspacing="0" cellpadding="0" style="width:100%;border-collapse:collapse;">
            <tr><td style="padding:8px 0;border-bottom:1px solid #2b2b2b;color:#9f9a90;font-size:13px;width:80px;">Name</td><td style="padding:8px 0 8px 16px;border-bottom:1px solid #2b2b2b;color:#f5f1e8;font-size:14px;">${escapeHtml(name)}</td></tr>
            <tr><td style="padding:8px 0;border-bottom:1px solid #2b2b2b;color:#9f9a90;font-size:13px;">Email</td><td style="padding:8px 0 8px 16px;border-bottom:1px solid #2b2b2b;color:#f5f1e8;font-size:14px;"><a href="mailto:${escapeHtml(email)}" style="color:#abd9d0;">${escapeHtml(email)}</a></td></tr>
            <tr><td style="padding:8px 0;color:#9f9a90;font-size:13px;">Subject</td><td style="padding:8px 0 8px 16px;color:#f5f1e8;font-size:14px;">${escapeHtml(subject)}</td></tr>
          </table>
        </div>
        <div style="border:1px solid #2b2b2b;background:#111;padding:24px;">
          <p style="font-size:12px;letter-spacing:0.12em;text-transform:uppercase;color:#9f9a90;margin:0 0 16px;">Message</p>
          <div style="font-size:14px;color:#c8c1b5;line-height:1.8;">${lines}</div>
        </div>
      </div>
    </div>
  `;
}

export async function POST(req: NextRequest): Promise<NextResponse> {
  const ip = getClientIp(req);
  const { allowed, retryAfterSec } = checkRateLimit(`contact:${ip}`, 5, 60 * 60 * 1000);
  if (!allowed) {
    return NextResponse.json(
      { error: 'Too many requests. Please try again later.' },
      { status: 429, headers: { 'Retry-After': String(retryAfterSec) } },
    );
  }

  let body: unknown;
  try {
    body = await req.json();
  } catch {
    return NextResponse.json({ error: 'Invalid request' }, { status: 400 });
  }

  if (!isRecord(body)) {
    return NextResponse.json({ error: 'Invalid request' }, { status: 400 });
  }

  const name = readString(body['name'], MAX_NAME_LENGTH);
  const email = readString(body['email'], 320);
  const subject = readString(body['subject'], MAX_SUBJECT_LENGTH);
  const message = readString(body['message'], MAX_MESSAGE_LENGTH);

  if (name.length === 0) return NextResponse.json({ error: 'Name is required.' }, { status: 400 });
  if (!EMAIL_RE.test(email)) return NextResponse.json({ error: 'A valid email address is required.' }, { status: 400 });
  if (subject.length === 0) return NextResponse.json({ error: 'Subject is required.' }, { status: 400 });
  if (message.length < 10) return NextResponse.json({ error: 'Message is too short.' }, { status: 400 });

  const resendApiKey = process.env['RESEND_API_KEY']?.trim() ?? '';
  if (resendApiKey === '') {
    // No email service configured — acknowledge without sending.
    return NextResponse.json({ ok: true });
  }

  const resendContactEmail = process.env['RESEND_CONTACT_EMAIL']?.trim() ?? '';
  const resendFromEmail = process.env['RESEND_FROM_EMAIL']?.trim() ?? '';
  const toEmail = resendContactEmail !== '' ? resendContactEmail : resendFromEmail;
  if (toEmail === '') {
    return NextResponse.json({ ok: true });
  }

  const from = resendFromEmail !== '' ? `STARGATER <${resendFromEmail}>` : 'STARGATER <orders@arcana.store>';

  try {
    const resend = new Resend(resendApiKey);
    await resend.emails.send({
      from,
      to: toEmail,
      replyTo: email,
      subject: `Contact: ${subject}`,
      html: buildContactEmailHtml(name, email, subject, message),
    });
  } catch {
    return NextResponse.json({ error: 'Failed to send message. Please try again later.' }, { status: 502 });
  }

  return NextResponse.json({ ok: true });
}

import { type NextRequest, NextResponse } from 'next/server';
import { checkRateLimit, getClientIp } from '@/lib/rate-limit';
import { getDb } from '@/lib/mongodb';
import { ensureAppIndexes } from '@/lib/db-indexes';

const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

export async function POST(req: NextRequest): Promise<NextResponse> {
  const ip = getClientIp(req);
  const { allowed, retryAfterSec } = checkRateLimit(`newsletter:${ip}`, 5, 60 * 60 * 1000);
  if (!allowed) {
    return NextResponse.json(
      { error: 'Too many requests. Please try again later.' },
      { status: 429, headers: { 'Retry-After': String(retryAfterSec) } },
    );
  }

  let body: unknown;
  try {
    body = await req.json();
  } catch {
    return NextResponse.json({ error: 'Invalid request' }, { status: 400 });
  }

  const email =
    typeof body === 'object' && body !== null && 'email' in body && typeof (body as Record<string, unknown>)['email'] === 'string'
      ? ((body as Record<string, unknown>)['email'] as string).trim().toLowerCase().slice(0, 320)
      : '';

  if (!EMAIL_RE.test(email)) {
    return NextResponse.json({ error: 'A valid email address is required.' }, { status: 400 });
  }

  void ensureAppIndexes();

  try {
    const db = await getDb();
    await db.collection('newsletter_subscribers').updateOne(
      { email },
      { $setOnInsert: { email, subscribedAt: new Date().toISOString() } },
      { upsert: true },
    );
  } catch {
    // DB unavailable — acknowledge silently rather than surfacing infra errors to the user.
  }

  return NextResponse.json({ ok: true });
}

import { NextResponse, type NextRequest } from 'next/server';
import { getMentiosProducts } from '@/lib/mentios';
import { PRODUCTS } from '@/data/products';
import { normalizeLocale } from '@/lib/locales';
import { checkRateLimit, getClientIp } from '@/lib/rate-limit';

export const dynamic = 'force-dynamic';

const MAX_CATALOG_FILTER_ITEMS = 60;
const MAX_QUERY_TEXT_LENGTH = 250;
const MAX_IDS = 200;
const MAX_SKIP = 5_000;

function parseFilterList(searchParams: URLSearchParams, key: string): string[] {
  const seen = new Set<string>();
  const result: string[] = [];
  for (const raw of searchParams.getAll(key)) {
    for (const item of raw.split(',')) {
      const normalized = item.trim();
      if (normalized.length === 0 || seen.has(normalized)) continue;
      seen.add(normalized);
      result.push(normalized);
    }
  }
  return result;
}

function parseLimit(value: string | null, fallback: number, max: number): number {
  const parsed = Number(value);
  if (!Number.isFinite(parsed) || !Number.isInteger(parsed) || parsed < 1) return fallback;
  return Math.min(max, parsed);
}

function parseSkip(value: string | null): number {
  const parsed = Number(value);
  if (!Number.isFinite(parsed) || !Number.isInteger(parsed) || parsed < 0) return 0;
  return Math.min(parsed, MAX_SKIP);
}

function sanitizeIds(raw: string | null): string[] {
  if (raw === null || raw.length === 0) return [];
  return raw
    .split(',')
    .map((value) => value.trim())
    .filter((value) => value.length > 0 && value.length <= 64)
    .slice(0, MAX_IDS);
}

function clampText(value: string | null | undefined): string | undefined {
  if (value === null || value === undefined) return undefined;
  const normalized = value.trim();
  if (normalized.length === 0) return undefined;
  return normalized.slice(0, MAX_QUERY_TEXT_LENGTH);
}

const VALID_SORT_VALUES = new Set(['featured', 'price-asc', 'price-desc', 'newest', 'name-asc', 'name-desc', 'category']);

function isValidSort(value: string | null | undefined): boolean {
  if (value === null || value === undefined || value.length === 0) return true;
  return VALID_SORT_VALUES.has(value);
}

function productMatchesThemes(product: { lore?: string; name: string }, themes: string[]): boolean {
  if (themes.length === 0) return true;
  const lore = product.lore?.toLowerCase() ?? '';
  const name = product.name.toLowerCase();
  return themes.some((theme) => {
    const query = theme.toLowerCase();
    return lore.includes(query) || name.includes(query);
  });
}

function hasResultFilters(input: {
  categoryNames: string[];
  collectionSlug: string | undefined;
  ids: string[];
  newOnly: boolean;
  priceMax: number | undefined;
  priceMin: number | undefined;
  search: string | undefined;
  themeNames: string[];
}): boolean {
  return (
    input.collectionSlug !== undefined ||
    input.categoryNames.length > 0 ||
    input.themeNames.length > 0 ||
    input.search !== undefined ||
    input.ids.length > 0 ||
    input.newOnly ||
    input.priceMin !== undefined ||
    input.priceMax !== undefined
  );
}

// eslint-disable-next-line max-lines-per-function, complexity
export async function GET(req: NextRequest): Promise<NextResponse> {
  const ip = getClientIp(req);
  const { allowed, retryAfterSec } = checkRateLimit(`products-api:${ip}`, 60, 60_000);
  if (!allowed) {
    return NextResponse.json(
      { error: 'Too many requests. Please slow down.' },
      { status: 429, headers: { 'Retry-After': String(retryAfterSec) } },
    );
  }
  const { searchParams } = req.nextUrl;
  const collectionSlug = searchParams.get('collection') ?? undefined;
  const categoryName = searchParams.get('category') ?? undefined;
  const rawCollectionSlug = collectionSlug?.trim();
  const rawCategoryName = categoryName?.trim();
  if (rawCollectionSlug !== undefined && rawCollectionSlug.length > MAX_QUERY_TEXT_LENGTH) {
    return NextResponse.json({ error: 'Invalid collection filter' }, { status: 400 });
  }
  if (rawCategoryName !== undefined && rawCategoryName.length > MAX_QUERY_TEXT_LENGTH) {
    return NextResponse.json({ error: 'Invalid category filter' }, { status: 400 });
  }

  const categoryNames = [
    ...parseFilterList(searchParams, 'categories'),
    ...(rawCategoryName === undefined ? [] : [rawCategoryName]),
  ];
  const themeNames = parseFilterList(searchParams, 'themes');
  const materialNames = parseFilterList(searchParams, 'materials');
  const sizeNames = parseFilterList(searchParams, 'sizes');
  const loreNames = parseFilterList(searchParams, 'lores');
  const search = searchParams.get('q') ?? undefined;
  const limit = parseLimit(searchParams.get('limit'), 100, 200);
  const skip = parseSkip(searchParams.get('skip'));
  const ids = sanitizeIds(searchParams.get('ids'));
  const newOnly = searchParams.get('new') === '1';
  const localeValue = clampText(searchParams.get('locale') ?? req.headers.get('x-ecom-locale'));
  const locale = normalizeLocale(localeValue ?? null);
  const sort = clampText(searchParams.get('sort'));
  const priceMinRaw = clampText(searchParams.get('priceMin'));
  const priceMaxRaw = clampText(searchParams.get('priceMax'));
  const priceMin = priceMinRaw === undefined ? undefined : Number(priceMinRaw);
  const priceMax = priceMaxRaw === undefined ? undefined : Number(priceMaxRaw);

  const safeCategoryName = clampText(rawCategoryName);
  const safeCollectionSlug = clampText(rawCollectionSlug);

  if (search !== undefined && search.length > MAX_QUERY_TEXT_LENGTH) {
    return NextResponse.json({ error: 'Search query is too long' }, { status: 400 });
  }
  if (!isValidSort(sort)) {
    return NextResponse.json({ error: 'Invalid sort' }, { status: 400 });
  }
  if (themeNames.length > MAX_CATALOG_FILTER_ITEMS || categoryNames.length > MAX_CATALOG_FILTER_ITEMS ||
      materialNames.length > MAX_CATALOG_FILTER_ITEMS || sizeNames.length > MAX_CATALOG_FILTER_ITEMS ||
      loreNames.length > MAX_CATALOG_FILTER_ITEMS) {
    return NextResponse.json({ error: 'Too many filter values' }, { status: 400 });
  }
  for (const value of [...themeNames, ...categoryNames, ...materialNames, ...sizeNames, ...loreNames]) {
    if (value.length > MAX_QUERY_TEXT_LENGTH) {
      return NextResponse.json({ error: 'Invalid filter value length' }, { status: 400 });
    }
  }
  if ((priceMin !== undefined && (!Number.isFinite(priceMin) || priceMin < 0)) ||
      (priceMax !== undefined && (!Number.isFinite(priceMax) || priceMax < 0))) {
    return NextResponse.json({ error: 'Invalid price filters' }, { status: 400 });
  }
  if (priceMin !== undefined && priceMax !== undefined && priceMin > priceMax) {
    return NextResponse.json({ error: 'Invalid price range' }, { status: 400 });
  }

  const { products, total } = await getMentiosProducts({
    limit,
    skip,
    collectionSlug: safeCollectionSlug,
    categoryName: safeCategoryName,
    categoryNames,
    themeNames,
    loreNames,
    search: search?.slice(0, MAX_QUERY_TEXT_LENGTH),
    ids,
    newOnly,
    locale,
    sort,
    priceMin,
    priceMax,
  });
  const hasFilters = hasResultFilters({
    categoryNames,
    collectionSlug: safeCollectionSlug,
    ids,
    newOnly,
    priceMax,
    priceMin,
    search: search?.slice(0, MAX_QUERY_TEXT_LENGTH),
    themeNames,
  });

  // Fall back to static demo products when DB is not configured or empty.
  if (products.length === 0 && total === 0 && !hasFilters) {
    let staticProducts = (collectionSlug === undefined
      ? PRODUCTS
      : PRODUCTS.filter((p) => p.collectionSlug === collectionSlug)
    ).filter((p) => p.isSoldOut !== true);

    if (categoryNames.length > 0) {
      const selected = new Set(categoryNames);
      staticProducts = staticProducts.filter((p) => selected.has(p.category));
    }

    if (themeNames.length > 0) {
      staticProducts = staticProducts.filter((p) => productMatchesThemes(p, themeNames));
    }

    if (materialNames.length > 0) {
      const materialSet = new Set(materialNames.map((m) => m.toLowerCase()));
      staticProducts = staticProducts.filter((p) => {
        const segments = p.name.split('|');
        const rawMat = p.material ?? segments[2] ?? '';
        const mat = rawMat.trim().toLowerCase();
        return mat.length > 0 && materialSet.has(mat);
      });
    }

    if (sizeNames.length > 0) {
      const sizeSet = new Set(sizeNames.map((s) => s.toLowerCase()));
      staticProducts = staticProducts.filter((p) => {
        const segments = p.name.split('|');
        const rawSize = p.sizeInfo ?? segments[1] ?? '';
        const sz = rawSize.trim().toLowerCase();
        return sz.length > 0 && sizeSet.has(sz);
      });
    }

    if (loreNames.length > 0) {
      const loreSet = new Set(loreNames.map((l) => l.toLowerCase()));
      staticProducts = staticProducts.filter((p) => {
        const segments = p.name.split('|');
        const rawLore = p.lore ?? segments[4] ?? '';
        const lr = rawLore.trim().toLowerCase();
        return lr.length > 0 && loreSet.has(lr);
      });
    }

    if (search !== undefined) {
      const q = search.toLowerCase();
      staticProducts = staticProducts.filter(
        (p) =>
          p.name.toLowerCase().includes(q) ||
          p.category.toLowerCase().includes(q) ||
          p.description.toLowerCase().includes(q),
      );
    }

    if (ids.length > 0) {
      const requested = new Set(ids);
      staticProducts = staticProducts.filter((p) => requested.has(p.id));
    }

    if (priceMin !== undefined) staticProducts = staticProducts.filter((p) => p.price >= priceMin);
    if (priceMax !== undefined) staticProducts = staticProducts.filter((p) => p.price < priceMax);

    if (sort === 'price-asc') staticProducts = [...staticProducts].sort((a, b) => a.price - b.price);
    else if (sort === 'price-desc') staticProducts = [...staticProducts].sort((a, b) => b.price - a.price);
    else if (sort === 'name-asc') staticProducts = [...staticProducts].sort((a, b) => (a.shortName ?? a.name).localeCompare(b.shortName ?? b.name));
    else if (sort === 'name-desc') staticProducts = [...staticProducts].sort((a, b) => (b.shortName ?? b.name).localeCompare(a.shortName ?? a.name));
    else if (sort === 'category') staticProducts = [...staticProducts].sort((a, b) => a.category.localeCompare(b.category));

    return NextResponse.json({
      products: staticProducts.slice(skip, skip + limit),
      total: staticProducts.length,
      source: 'static',
    });
  }

  return NextResponse.json({ products, total, source: 'mentios' });
}

import { type NextRequest, NextResponse } from 'next/server';
import { getDb } from '@/lib/mongodb';
import { ORDERS_COLLECTION, type Order, serializeOrder } from '@/lib/orders';
import { verifyPayPalWebhook } from '@/lib/paypal';
import { sendOrderConfirmation } from '@/lib/email';
import { fulfillInpostOrder } from '@/lib/inpost';

type PayPalWebhookEvent = {
  event_type?: string;
  resource?: {
    id?: string;
    status?: string;
    purchase_units?: Array<{ reference_id?: string }>;
    supplementary_data?: {
      related_ids?: { order_id?: string };
    };
  };
};

function mapPayPalStatus(eventType: string): Order['status'] | null {
  switch (eventType) {
    case 'PAYMENT.CAPTURE.COMPLETED':
    case 'CHECKOUT.ORDER.COMPLETED':
      return 'processing';
    case 'PAYMENT.CAPTURE.DENIED':
    case 'PAYMENT.CAPTURE.DECLINED':
    case 'CHECKOUT.ORDER.VOIDED':
      return 'cancelled';
    default:
      return null;
  }
}

function extractPayPalOrderId(event: PayPalWebhookEvent): string {
  const referenceId = event.resource?.purchase_units?.[0]?.reference_id?.trim() ?? '';
  if (referenceId !== '') return referenceId.toUpperCase();
  const supplementaryOrderId = event.resource?.supplementary_data?.related_ids?.order_id?.trim() ?? '';
  return supplementaryOrderId.toUpperCase();
}

export async function POST(req: NextRequest): Promise<NextResponse> {
  const rawBody = await req.text();

  const verified = await verifyPayPalWebhook(rawBody, {
    'paypal-auth-algo': req.headers.get('paypal-auth-algo'),
    'paypal-cert-url': req.headers.get('paypal-cert-url'),
    'paypal-transmission-id': req.headers.get('paypal-transmission-id'),
    'paypal-transmission-sig': req.headers.get('paypal-transmission-sig'),
    'paypal-transmission-time': req.headers.get('paypal-transmission-time'),
  });

  if (!verified) {
    return NextResponse.json({ error: 'Invalid signature' }, { status: 401 });
  }

  let event: PayPalWebhookEvent;
  try {
    event = JSON.parse(rawBody) as PayPalWebhookEvent;
  } catch {
    return NextResponse.json({ error: 'Invalid JSON' }, { status: 400 });
  }

  const eventType = event.event_type ?? '';
  const newStatus = mapPayPalStatus(eventType);
  if (newStatus === null) {
    return NextResponse.json({ received: true });
  }

  const paypalCaptureId = event.resource?.id?.trim() ?? '';
  const localOrderId = extractPayPalOrderId(event);

  if (paypalCaptureId === '' && localOrderId === '') {
    return NextResponse.json({ error: 'Missing order reference' }, { status: 400 });
  }

  const db = await getDb();
  const collection = db.collection(ORDERS_COLLECTION);

  const candidates: Record<string, string>[] = [];
  if (localOrderId !== '') candidates.push({ orderId: localOrderId });
  if (paypalCaptureId !== '') candidates.push({ paypalOrderId: paypalCaptureId });
  const filter = candidates.length === 1 ? candidates[0] : { $or: candidates };

  const order = await collection.findOneAndUpdate(
    filter,
    { $set: { status: newStatus } },
    { returnDocument: 'after' },
  );

  if (order === null) {
    return NextResponse.json({ error: 'Order not found' }, { status: 404 });
  }

  if (newStatus === 'processing') {
    // Atomic guard: claim the right to send the confirmation email exactly once,
    // even when PayPal retries the webhook on transient failures.
    const emailClaim = await collection.updateOne(
      { _id: order._id, confirmationEmailQueuedAt: { $exists: false } },
      { $set: { confirmationEmailQueuedAt: new Date().toISOString() } },
    );
    if (emailClaim.modifiedCount > 0) {
      await sendOrderConfirmation(serializeOrder(order)).catch(() => undefined);
      await fulfillInpostOrder(serializeOrder(order)).catch(() => undefined);
    }
  }

  return NextResponse.json({ received: true });
}

import { type NextRequest, NextResponse } from 'next/server';
import { getDb } from '@/lib/mongodb';
import { ORDERS_COLLECTION, type Order, serializeOrder } from '@/lib/orders';
import { verifyStripeWebhook } from '@/lib/stripe';
import { sendOrderConfirmation } from '@/lib/email';
import { fulfillInpostOrder } from '@/lib/inpost';

type StripeEvent = {
  type?: string;
  data?: {
    object?: {
      id?: string;
      metadata?: Record<string, string>;
      status?: string;
    };
  };
};

function mapStripeStatus(stripeStatus: string): Order['status'] | null {
  switch (stripeStatus) {
    case 'succeeded':
      return 'processing';
    case 'canceled':
      return 'cancelled';
    case 'requires_payment_method':
    case 'processing':
    case 'requires_action':
    case 'requires_confirmation':
    case 'requires_capture':
      return 'pending_payment';
    default:
      return null;
  }
}

export async function POST(req: NextRequest): Promise<NextResponse> {
  const rawBody = await req.text();
  const signatureHeader = req.headers.get('stripe-signature');

  if (!(await verifyStripeWebhook(rawBody, signatureHeader))) {
    return NextResponse.json({ error: 'Invalid signature' }, { status: 401 });
  }

  let event: StripeEvent;
  try {
    event = JSON.parse(rawBody) as StripeEvent;
  } catch {
    return NextResponse.json({ error: 'Invalid JSON' }, { status: 400 });
  }

  const eventType = event.type ?? '';
  if (!eventType.startsWith('payment_intent.')) {
    return NextResponse.json({ received: true });
  }

  const paymentIntent = event.data?.object;
  const paymentIntentId = paymentIntent?.id?.trim() ?? '';
  const orderId = paymentIntent?.metadata?.orderId?.trim().toUpperCase() ?? '';
  const stripeStatus = paymentIntent?.status ?? '';

  if (paymentIntentId === '') {
    return NextResponse.json({ error: 'Missing payment intent ID' }, { status: 400 });
  }

  const newStatus = mapStripeStatus(stripeStatus);
  if (newStatus === null) {
    return NextResponse.json({ received: true });
  }

  const db = await getDb();
  const collection = db.collection(ORDERS_COLLECTION);

  const filter = orderId !== ''
    ? { $or: [{ stripePaymentIntentId: paymentIntentId }, { orderId }] }
    : { stripePaymentIntentId: paymentIntentId };

  const order = await collection.findOneAndUpdate(
    filter,
    { $set: { status: newStatus } },
    { returnDocument: 'after' },
  );

  if (order === null) {
    return NextResponse.json({ error: 'Order not found' }, { status: 404 });
  }

  if (newStatus === 'processing') {
    // Atomic guard: claim the right to send the confirmation email exactly once,
    // even when Stripe retries the webhook on transient failures.
    const emailClaim = await collection.updateOne(
      { _id: order._id, confirmationEmailQueuedAt: { $exists: false } },
      { $set: { confirmationEmailQueuedAt: new Date().toISOString() } },
    );
    if (emailClaim.modifiedCount > 0) {
      await sendOrderConfirmation(serializeOrder(order)).catch(() => undefined);
      await fulfillInpostOrder(serializeOrder(order)).catch(() => undefined);
    }
  }

  return NextResponse.json({ received: true });
}

