                </div>
              </div>
            )}
          </div>

          {/* Order summary column */}
          <div className='px-8 md:px-10 py-12' style={{ background: 'var(--surface)', borderLeft: '1px solid var(--border)' }}>
            <OrderSummary
              content={content.orderSummary}
              displayItems={checkoutItems}
              pricingRefreshPending={cartRefreshPending}
              shippingPrice={selectedShipping.price}
              subtotal={subtotal}
              discount={discount}
              total={total}
              freeShippingThreshold={content.freeShippingThreshold}
              freeShippingBannerLabel={content.freeShippingBannerLabel}
              promoCode={promoCode}
              promoDiscountType={promoDiscountType}
              promoDiscountValue={promoDiscountValue}
              customerEmail={form.email ?? ''}
              onPromoCodeChange={handlePromoCodeChange}
            />
          </div>
        </div>
      </main>
    </>
  );
}

import { z } from 'zod';
import type { EcomLocale } from '@/lib/locales';

export function buildCheckoutInfoSchema(locale: EcomLocale): z.ZodObject<any> {
  const req = locale === 'pl' ? 'To pole jest wymagane.' : 'This field is required.';
  const emailInvalid = locale === 'pl' ? 'Wpisz poprawny adres email.' : 'Enter a valid email address.';
  const phoneInvalid = locale === 'pl' ? 'Wpisz poprawny numer telefonu.' : 'Enter a valid phone number.';

  return z.object({
    email: z.string().min(1, req).email(emailInvalid),
    firstName: z.string().min(1, req),
    lastName: z.string().min(1, req),
    address: z.string().min(1, req),
    apartment: z.string().optional(),
    city: z.string().min(1, req),
    postcode: z.string().min(1, req),
    country: z.string().min(1, req),
    phone: z.string().optional().refine(
      (val) => val === undefined || val === null || val.trim() === '' || /^[+\d][\d\s\-()+.]{5,}$/.test(val.trim()),
      { message: phoneInvalid },
    ),
  });
}

export type CheckoutInfoData = z.infer<ReturnType<typeof buildCheckoutInfoSchema>>;

