              >
                    {brandName}
              </span>
              <span className='type-label' style={{ color: 'rgba(var(--accent-rgb),0.45)' }}>{brandSuffix}</span>
            </div>
            <p
              className='type-label max-w-xs mb-6'
              style={{ color: 'var(--muted-teal)', lineHeight: 1.9, letterSpacing: '0.08em' }}
